import{c as e,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Language Agent Tree Search (LATS)","description":"","frontmatter":{"title":"Language Agent Tree Search (LATS)","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2310.04406-lats-arxiv.md","filePath":"research/agent-harness/references/2310.04406-lats-arxiv.md","lastUpdated":1779894392000}'),s={name:"research/agent-harness/references/2310.04406-lats-arxiv.md"};function o(i,a,l,h,d,c){return t(),r("div",null,[...a[0]||(a[0]=[n(`<h1 id="language-agent-tree-search-lats" tabindex="-1">Language Agent Tree Search (LATS) <a class="header-anchor" href="#language-agent-tree-search-lats" aria-label="Permalink to &quot;Language Agent Tree Search (LATS)&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2310.04406" target="_blank" rel="noreferrer">https://arxiv.org/abs/2310.04406</a></li><li><strong>發表</strong>: ICML 2024</li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority B — 將 ReAct 的線性 loop 升級為樹狀搜索；Tree search 控制原語的學術依據</li></ul><hr><h2 id="核心創新-統一推理、行動、規劃" tabindex="-1">核心創新：統一推理、行動、規劃 <a class="header-anchor" href="#核心創新-統一推理、行動、規劃" aria-label="Permalink to &quot;核心創新：統一推理、行動、規劃&quot;">​</a></h2><p>LATS = Language Agent Tree Search</p><p>將蒙地卡洛樹搜索（MCTS）整合進 LLM agent 框架，同時統一三個維度：</p><table tabindex="0"><thead><tr><th>維度</th><th>ReAct 的處理</th><th>LATS 的處理</th></tr></thead><tbody><tr><td><strong>Reasoning</strong></td><td>線性 CoT</td><td>樹狀節點探索</td></tr><tr><td><strong>Acting</strong></td><td>依序執行</td><td>平行探索多條 action 路徑</td></tr><tr><td><strong>Planning</strong></td><td>隱式（prompt 中）</td><td>顯式 value function 引導</td></tr></tbody></table><hr><h2 id="架構設計" tabindex="-1">架構設計 <a class="header-anchor" href="#架構設計" aria-label="Permalink to &quot;架構設計&quot;">​</a></h2><h3 id="核心組件" tabindex="-1">核心組件 <a class="header-anchor" href="#核心組件" aria-label="Permalink to &quot;核心組件&quot;">​</a></h3><ol><li><strong>LM-powered Value Function</strong>：語言模型評估每個狀態的「前景」（promise），引導樹搜索方向</li><li><strong>Self-Reflection</strong>：訪問被剪枝的分支，提取有用的洞見注入後續搜索</li><li><strong>External Environment Feedback</strong>：來自工具/環境的反饋作為搜索的獎勵信號</li></ol><h3 id="mcts-四步驟-在語言空間的應用" tabindex="-1">MCTS 四步驟（在語言空間的應用） <a class="header-anchor" href="#mcts-四步驟-在語言空間的應用" aria-label="Permalink to &quot;MCTS 四步驟（在語言空間的應用）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Selection: 選擇最有前景的節點（UCB 公式 + LM 評估）</span></span>
<span class="line"><span>2. Expansion: 展開新的 thought/action 組合</span></span>
<span class="line"><span>3. Evaluation: LM 評估節點品質</span></span>
<span class="line"><span>4. Backpropagation: 更新父節點的 value 估計</span></span></code></pre></div><hr><h2 id="實驗成果" tabindex="-1">實驗成果 <a class="header-anchor" href="#實驗成果" aria-label="Permalink to &quot;實驗成果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>LATS（GPT-4）</th><th>基線</th></tr></thead><tbody><tr><td>HumanEval pass@1</td><td><strong>92.7%</strong></td><td>~80%（純 ReAct）</td></tr><tr><td>WebShop 導航</td><td><strong>75.9</strong></td><td>~70（基線）</td></tr></tbody></table><hr><h2 id="對-harness-engineering-的影響" tabindex="-1">對 Harness Engineering 的影響 <a class="header-anchor" href="#對-harness-engineering-的影響" aria-label="Permalink to &quot;對 Harness Engineering 的影響&quot;">​</a></h2><h3 id="洞見-1-tree-search-是所有架構的「探索加速器」" tabindex="-1">洞見 #1：Tree Search 是所有架構的「探索加速器」 <a class="header-anchor" href="#洞見-1-tree-search-是所有架構的「探索加速器」" aria-label="Permalink to &quot;洞見 #1：Tree Search 是所有架構的「探索加速器」&quot;">​</a></h3><p>Scaffold Taxonomy（2604.03515）列出的 5 個控制原語中，Tree search 是最複雜也最強大的。LATS 提供了它的學術基礎。</p><h3 id="洞見-2-value-function-可以用語言模型實現" tabindex="-1">洞見 #2：Value Function 可以用語言模型實現 <a class="header-anchor" href="#洞見-2-value-function-可以用語言模型實現" aria-label="Permalink to &quot;洞見 #2：Value Function 可以用語言模型實現&quot;">​</a></h3><p>不需要額外訓練的 reward model，只需要讓 LLM「評估這個路徑有多好」。這降低了 tree search 的實作門檻，使其在 harness 中可行。</p><h3 id="洞見-3-被剪枝的路徑也有價值" tabindex="-1">洞見 #3：被剪枝的路徑也有價值 <a class="header-anchor" href="#洞見-3-被剪枝的路徑也有價值" aria-label="Permalink to &quot;洞見 #3：被剪枝的路徑也有價值&quot;">​</a></h3><p>LATS 的 Self-Reflection 機制從「失敗的分支」中提取知識，對應 Ratchet 原則：即使是失敗的嘗試也應該沉澱成知識。</p><hr><h2 id="與-ahe-2604-25850-的關係" tabindex="-1">與 AHE（2604.25850）的關係 <a class="header-anchor" href="#與-ahe-2604-25850-的關係" aria-label="Permalink to &quot;與 AHE（2604.25850）的關係&quot;">​</a></h2><p>LATS 的「值函數引導探索」啟發了 AHE 的「決策可觀測性」：</p><ul><li>LATS：每個節點有明確的 value 估計</li><li>AHE：每次 harness 編輯配對「自我宣告的預測」+ 驗證</li></ul><p>兩者都把決策過程「顯式化」，使其可追蹤和可改進。</p><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv: <a href="https://arxiv.org/abs/2310.04406" target="_blank" rel="noreferrer">https://arxiv.org/abs/2310.04406</a></li></ul>`,31)])])}const u=e(s,[["render",o]]);export{p as __pageData,u as default};
